package com.google.gson.internal;

import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.internal.bind.TypeAdapters;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;

class StreamsTest {

  @Test
  void write_invokesTypeAdaptersJsonElementWrite() throws IOException {
    JsonElement element = mock(JsonElement.class);
    JsonWriter writer = mock(JsonWriter.class);

    try (MockedStatic<TypeAdapters> mockedTypeAdapters = mockStatic(TypeAdapters.class)) {
      var jsonElementAdapter = mock(TypeAdapters.JSON_ELEMENT.getClass());
      // TypeAdapters.JSON_ELEMENT is a static final field of type TypeAdapter<JsonElement>
      // We need to mock its write method.
      // But TypeAdapters.JSON_ELEMENT is static final. We can mock the static field by mocking the TypeAdapters class static field.

      // Instead, we can spy on TypeAdapters.JSON_ELEMENT
      // But TypeAdapters.JSON_ELEMENT is a static final field, so we can use reflection to replace it temporarily or just verify the call.

      // Alternative: We can use Mockito's spy on TypeAdapters.JSON_ELEMENT (which is a TypeAdapter<JsonElement>)
      // But TypeAdapters.JSON_ELEMENT is public static final TypeAdapter<JsonElement> JSON_ELEMENT;
      // So we can spy on it.

      var jsonElementAdapterSpy = spy(TypeAdapters.JSON_ELEMENT);
      // Use reflection to replace TypeAdapters.JSON_ELEMENT with the spy temporarily

      var jsonElementField = TypeAdapters.class.getDeclaredField("JSON_ELEMENT");
      jsonElementField.setAccessible(true);
      var original = jsonElementField.get(null);
      try {
        jsonElementField.set(null, jsonElementAdapterSpy);
        Streams.write(element, writer);
        verify(jsonElementAdapterSpy).write(writer, element);
      } finally {
        jsonElementField.set(null, original);
      }
    } catch (NoSuchFieldException | IllegalAccessException e) {
      throw new RuntimeException(e);
    }
  }
}
